// RawrXD Agentic Core — Express + React server demo
// Generated by: RawrXD Win32IDE autonomous agent
// Serves a React app on port 3000 with an /api/hello endpoint

const express = require('express');
const cors    = require('cors');
const path    = require('path');

const app  = express();
const PORT = process.env.PORT || 3000;

app.use(cors());
app.use(express.json());

// ─── API routes ─────────────────────────────────────────────
app.get('/api/hello', (_req, res) => {
    res.json({ message: 'Hello from RawrXD agentic core' });
});

app.get('/api/status', (_req, res) => {
    res.json({
        status:    'running',
        engine:    'RawrXD-Win32IDE',
        version:   '2026-04-12',
        uptime_ms: process.uptime() * 1000 | 0,
    });
});

// ─── React app inline (no build step required) ──────────────
const htmlShell = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width,initial-scale=1" />
<title>RawrXD Agentic Demo</title>
<style>
  body { font-family: -apple-system, 'Segoe UI', sans-serif; background: #0d1117; color: #c9d1d9; margin: 0; display: flex; justify-content: center; align-items: center; min-height: 100vh; }
  .card { background: #161b22; border: 1px solid #30363d; border-radius: 12px; padding: 2rem 2.5rem; max-width: 480px; width: 100%; box-shadow: 0 8px 32px rgba(0,0,0,0.4); }
  h1 { color: #58a6ff; margin: 0 0 1rem; font-size: 1.4rem; }
  .badge { display: inline-block; background: #238636; color: #fff; border-radius: 20px; padding: .2rem .8rem; font-size: .75rem; margin-bottom: 1rem; }
  .msg { font-size: 1.1rem; color: #3fb950; font-family: monospace; background: #0d1117; border-radius: 6px; padding: .75rem 1rem; word-break: break-all; }
  .loading { color: #8b949e; }
  .err { color: #f85149; }
  .meta { margin-top: 1.5rem; font-size: .8rem; color: #8b949e; }
</style>
</head>
<body>
<div id="root"></div>
<script>
// Minimal React-like runtime — no bundler needed
async function init() {
    const root = document.getElementById('root');
    root.innerHTML = '<div class="card"><h1>RawrXD Agentic Core</h1><div class="badge">LIVE</div><p class="loading">Loading…</p></div>';
    try {
        const [helloRes, statusRes] = await Promise.all([
            fetch('/api/hello'),
            fetch('/api/status')
        ]);
        const hello  = await helloRes.json();
        const status = await statusRes.json();
        root.innerHTML = \`
<div class="card">
  <h1>RawrXD Agentic Core</h1>
  <span class="badge">LIVE</span>
  <p class="msg">"\${hello.message}"</p>
  <div class="meta">
    <div>engine: \${status.engine}</div>
    <div>version: \${status.version}</div>
    <div>uptime: \${(status.uptime_ms / 1000).toFixed(1)}s</div>
  </div>
</div>\`;
    } catch (e) {
        root.innerHTML = \`<div class="card"><h1>RawrXD Agentic Core</h1><p class="err">Connection error: \${e.message}</p></div>\`;
    }
}
init();
</script>
</body>
</html>`;

app.get('*', (_req, res) => {
    res.send(htmlShell);
});

// ─── Start ───────────────────────────────────────────────────
app.listen(PORT, () => {
    console.log(`[RawrXD Agent] React+Express server running on http://localhost:${PORT}`);
    console.log(`[RawrXD Agent] API: http://localhost:${PORT}/api/hello`);
    console.log(`[RawrXD Agent] Status: http://localhost:${PORT}/api/status`);
});
